// Typed Gateway client. The TYPES come from the OpenAPI document the Gateway emits
// (src/api/schema.ts, generated by `npm run gen:api`), so the C# DTOs stay the single source
// of truth: a C# DTO change that is not reflected in a regenerated schema fails this build.
//
// The per-machine Gateway token is injected into index.html server-side (window.__GW_TOKEN__)
// and sent as a Bearer header, so the app authenticates whether global Gateway auth is on or
// off (the /sessions endpoint is reachable either way once the bearer is attached).
import type { components } from "./schema";

export type SessionDto = components["schemas"]["SessionDto"];

// Request bodies are typed from the generated OpenAPI schema (the C# DTOs stay the source of
// truth). The buffer/escape/interrupt/tts responses are not declared in the schema (the Gateway
// returns them via Results.Json/Results.Bytes without an [Produces] annotation), so they are
// read with narrow local shapes for exactly the fields the Terminal view consumes.
type PromptRequest = components["schemas"]["PromptRequest"];
type WingmanTtsRequest = components["schemas"]["WingmanTtsRequest"];

// The injected token. A value still starting with "__" means the page was served without
// injection (e.g. opened directly from the raw build) - treat that as absent.
function gatewayToken(): string {
  const raw =
    (typeof window !== "undefined" && (window as unknown as { __GW_TOKEN__?: string }).__GW_TOKEN__) || "";
  return raw.indexOf("__") === 0 ? "" : raw;
}

function authHeaders(): HeadersInit {
  const token = gatewayToken();
  return token ? { Authorization: `Bearer ${token}` } : {};
}

export class GatewayError extends Error {
  readonly status: number;
  constructor(status: number, message: string) {
    super(message);
    this.name = "GatewayError";
    this.status = status;
  }
}

// GET /sessions - the fleet roster aggregator. Returns the same SessionDto shape the Cockpit
// Mobile page consumes. Throws GatewayError on a non-2xx so the caller surfaces it (no silent
// fallback). The request is same-origin against the Gateway front door.
export async function listSessions(signal?: AbortSignal): Promise<SessionDto[]> {
  const res = await fetch("/sessions", {
    method: "GET",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `GET /sessions failed: ${res.status}`);
  }
  return (await res.json()) as SessionDto[];
}

// One incremental read of the session's raw terminal buffer for the live mirror. The new bytes
// since the previous cursor plus the cursor to pass on the next poll, so each poll fetches only
// fresh output. Pass since=null on the first call to dump the whole buffer (the server returns the
// full retained scrollback and the cursor at its end).
export interface BufferSlice {
  text: string;
  newCursor: number;
  totalBytes: number;
}

export async function getBuffer(
  sessionId: string,
  since: number | null,
  signal?: AbortSignal,
): Promise<BufferSlice> {
  const sid = encodeURIComponent(sessionId);
  // raw=true returns the verbatim PTY byte stream (ANSI/cursor control included) decoded as UTF-8,
  // exactly what an xterm.js emulator consumes to render a coherent screen. since advances the
  // cursor so the mirror is incremental, not a re-fetch of the whole buffer every poll.
  const url = since !== null && since >= 0
    ? `/sessions/${sid}/buffer?raw=true&since=${since}`
    : `/sessions/${sid}/buffer?raw=true`;
  const res = await fetch(url, {
    method: "GET",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `GET buffer failed: ${res.status}`);
  }
  const body = (await res.json()) as { text?: string; newCursor?: number; totalBytes?: number };
  return {
    text: body.text ?? "",
    newCursor: Number(body.newCursor ?? 0),
    totalBytes: Number(body.totalBytes ?? 0),
  };
}

// The ANSI-cleaned tail of the buffer (escape codes stripped by the server's own cleaner) for
// reading aloud - the raw mirror bytes carry control sequences that must not be spoken.
export async function getCleanTail(
  sessionId: string,
  lines: number,
  signal?: AbortSignal,
): Promise<string> {
  const sid = encodeURIComponent(sessionId);
  const res = await fetch(`/sessions/${sid}/buffer?raw=false&lines=${lines}`, {
    method: "GET",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `GET buffer (clean) failed: ${res.status}`);
  }
  const body = (await res.json()) as { text?: string };
  return body.text ?? "";
}

// Write text (or a raw key escape sequence) to the session's PTY. appendEnter=true submits a typed
// line (the Send button); appendEnter=false writes the bytes verbatim (Enter "\r", arrow keys
// ESC[A/B/C/D) so the session reacts as if the key were pressed at the terminal.
export async function sendPrompt(
  sessionId: string,
  text: string,
  appendEnter: boolean,
  signal?: AbortSignal,
): Promise<void> {
  const sid = encodeURIComponent(sessionId);
  const body: PromptRequest = { text, appendEnter };
  const res = await fetch(`/sessions/${sid}/prompt`, {
    method: "POST",
    headers: { "Content-Type": "application/json", Accept: "application/json", ...authHeaders() },
    body: JSON.stringify(body),
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `POST prompt failed: ${res.status}`);
  }
}

// Soft-stop the current turn (the agent driver's Escape). POST /sessions/{sid}/escape.
export async function sendEscape(sessionId: string, signal?: AbortSignal): Promise<void> {
  const sid = encodeURIComponent(sessionId);
  const res = await fetch(`/sessions/${sid}/escape`, {
    method: "POST",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `POST escape failed: ${res.status}`);
  }
}

// Interrupt a running agent turn (Ctrl+C). POST /sessions/{sid}/interrupt.
export async function sendInterrupt(sessionId: string, signal?: AbortSignal): Promise<void> {
  const sid = encodeURIComponent(sessionId);
  const res = await fetch(`/sessions/${sid}/interrupt`, {
    method: "POST",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `POST interrupt failed: ${res.status}`);
  }
}

// Text-to-speech of the latest output. POST /wingman/tts (the Gateway's OpenAI nova-voice proxy,
// no voice override) returns audio/mpeg bytes over plain HTTP - not a SignalR frame - which the
// caller plays in an <audio> element.
export async function synthesizeSpeech(text: string, signal?: AbortSignal): Promise<Blob> {
  const body: WingmanTtsRequest = { text };
  const res = await fetch(`/wingman/tts`, {
    method: "POST",
    headers: { "Content-Type": "application/json", ...authHeaders() },
    body: JSON.stringify(body),
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `POST wingman/tts failed: ${res.status}`);
  }
  return await res.blob();
}

// ===== Chat mode (#811): the cleaned conversation history =====
// The /turns, /summary and /wingman/explain responses are served via Results.Json without a
// [Produces] annotation, so (like buffer/escape/interrupt/tts above) they are not in the generated
// OpenAPI schema. They are read here with narrow local shapes for exactly the fields the Chat view
// consumes. .NET serialises minimal-API JSON camelCase, matching these property names.

// One widget ("card") in the cleaned transcript, parsed by the Director from claude.exe's JSONL
// log. kind is one of: Text, Thinking, UserMessage, Bash, Read, Write, Edit, Grep, Glob,
// TodoWrite, Agent, Skill, GenericTool, ... (see TurnWidgetDto on the server).
export interface TurnWidget {
  kind: string;
  header: string;
  subheader: string | null;
  content: string;
  result: string;
  isError: boolean;
  isPending: boolean;
  toolUseId: string;
}

export interface TurnsResult {
  status: string;
  widgets: TurnWidget[];
  lineCount: number;
  claudeSessionId: string | null;
  error: string | null;
}

// GET /sessions/{sid}/turns - the cleaned conversation as chronological widgets (assistant Text,
// user UserMessage, Thinking, and tool actions). status "ok" means widgets are populated; other
// values ("no_session_id" / "no_jsonl" / "parse_error") carry an error string and no widgets.
export async function getTurns(sessionId: string, signal?: AbortSignal): Promise<TurnsResult> {
  const sid = encodeURIComponent(sessionId);
  const res = await fetch(`/sessions/${sid}/turns`, {
    method: "GET",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `GET turns failed: ${res.status}`);
  }
  const body = (await res.json()) as {
    status?: string;
    widgets?: Partial<TurnWidget>[];
    lineCount?: number;
    claudeSessionId?: string | null;
    error?: string | null;
  };
  return {
    status: body.status ?? "",
    lineCount: Number(body.lineCount ?? 0),
    claudeSessionId: body.claudeSessionId ?? null,
    error: body.error ?? null,
    widgets: (body.widgets ?? []).map((w) => ({
      kind: w.kind ?? "",
      header: w.header ?? "",
      subheader: w.subheader ?? null,
      content: w.content ?? "",
      result: w.result ?? "",
      isError: Boolean(w.isError),
      isPending: Boolean(w.isPending),
      toolUseId: w.toolUseId ?? "",
    })),
  };
}

export interface SessionSummary {
  status: string;
  lastUserPrompt: string | null;
  lastAssistantText: string | null;
  activityState: string;
  turnCount: number;
  openTodos: { status: string; content: string }[];
  error: string | null;
}

// GET /sessions/{sid}/summary - a structured snapshot of the session (last prompt/reply, activity
// state, open todos). Drives the Chat view's compact context strip above the transcript.
export async function getSummary(sessionId: string, signal?: AbortSignal): Promise<SessionSummary> {
  const sid = encodeURIComponent(sessionId);
  const res = await fetch(`/sessions/${sid}/summary`, {
    method: "GET",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `GET summary failed: ${res.status}`);
  }
  const body = (await res.json()) as {
    status?: string;
    lastUserPrompt?: string | null;
    lastAssistantText?: string | null;
    activityState?: string;
    turnCount?: number;
    openTodos?: { status?: string; content?: string }[];
    error?: string | null;
  };
  return {
    status: body.status ?? "",
    lastUserPrompt: body.lastUserPrompt ?? null,
    lastAssistantText: body.lastAssistantText ?? null,
    activityState: body.activityState ?? "",
    turnCount: Number(body.turnCount ?? 0),
    error: body.error ?? null,
    openTodos: (body.openTodos ?? []).map((t) => ({
      status: t.status ?? "",
      content: t.content ?? "",
    })),
  };
}

export interface SessionExplain {
  mobileMode: boolean;
  text: string | null;
  headline: string | null;
  whatHappened: string | null;
  say: string | null;
}

// GET /sessions/{sid}/wingman/explain - the cached, cleaned explanation of the latest activity
// (headline + "what happened" + a short spoken form). Returns instantly (no LLM call); text is
// null when nothing is cached yet (mobile mode off, or the first turn has not finished). The Chat
// view shows the headline as a "latest, explained" card when present and otherwise omits it.
export async function getExplain(sessionId: string, signal?: AbortSignal): Promise<SessionExplain> {
  const sid = encodeURIComponent(sessionId);
  const res = await fetch(`/sessions/${sid}/wingman/explain`, {
    method: "GET",
    headers: { Accept: "application/json", ...authHeaders() },
    signal,
  });
  if (!res.ok) {
    throw new GatewayError(res.status, `GET wingman/explain failed: ${res.status}`);
  }
  const body = (await res.json()) as {
    mobileMode?: boolean;
    text?: string | null;
    headline?: string | null;
    whatHappened?: string | null;
    say?: string | null;
  };
  return {
    mobileMode: Boolean(body.mobileMode),
    text: body.text ?? null,
    headline: body.headline ?? null,
    whatHappened: body.whatHappened ?? null,
    say: body.say ?? null,
  };
}
